query.sql:
select DATE_FORMAT(p.cost_date, '#{@date_format}') as profit_period, ifnull(p.channel_pf,0) + ifnull(p.channel_zs,0) + ifnull(p.channel_jt,0) + ifnull(p.channel_al,0) + ifnull(p.channel_jj,0) as record_total, ifnull(p.channel_pf,0) as record_pf, ifnull(p.channel_zs,0) as record_zs, ifnull(p.channel_jt,0) as record_jt, ifnull(p.channel_al,0) as record_al, ifnull(p.channel_jj,0) as record_jj, ifnull(arc.archive_total, 0) as archive_total, ifnull(arc.archive_pf, 0) as archive_pf, ifnull(arc.archive_zs, 0) as archive_zs, ifnull(arc.archive_jt, 0) as archive_jt, ifnull(arc.archive_al, 0) as archive_al, ifnull(arc.archive_jj, 0) as archive_jj from pf_profit_record p left join ( select DATE_FORMAT(cost_date, '#{@date_format}') as archive_period, SUM(ifnull(channel_pf,0) + ifnull(channel_zs,0) + ifnull(channel_jt,0) + ifnull(channel_al,0) + ifnull(channel_jj,0)) as archive_total, SUM(ifnull(channel_pf,0)) as archive_pf, SUM(ifnull(channel_zs,0)) as archive_zs, SUM(ifnull(channel_jt,0)) as archive_jt, SUM(ifnull(channel_al,0)) as archive_al, SUM(ifnull(channel_jj,0)) as archive_jj from pf_profit_archive where book_id = ${@book_id}
and cost_date <= ${@cost_date}
group by DATE_FORMAT(cost_date, '#{@date_format}') ) arc on DATE_FORMAT(p.cost_date, '#{@date_format}') = arc.archive_period where p.cost_date in ( SELECT max(cost_date) FROM pf_profit_record where book_id = ${@book_id}
and cost_date <= ${@cost_date}
GROUP BY DATE_FORMAT(cost_date, '#{@date_format}') ) order by p.cost_date

SELECT IFNULL(latest.channel_pf, 0) AS current_channel_pf, IFNULL(latest.channel_zs, 0) AS current_channel_zs, IFNULL(latest.channel_jt, 0) AS current_channel_jt, IFNULL(latest.channel_al, 0) AS current_channel_al, IFNULL(latest.channel_jj, 0) AS current_channel_jj, IFNULL(latest.channel_pf, 0) + IFNULL(latest.channel_zs, 0) + IFNULL(latest.channel_jt, 0) + IFNULL(latest.channel_al, 0) + IFNULL(latest.channel_jj, 0) AS current_channel_total, IFNULL(arc.t_pf, 0) AS archived_channel_pf, IFNULL(arc.t_zs, 0) AS archived_channel_zs, IFNULL(arc.t_jt, 0) AS archived_channel_jt, IFNULL(arc.t_al, 0) AS archived_channel_al, IFNULL(arc.t_jj, 0) AS archived_channel_jj, IFNULL(arc.t_sum, 0) AS archived_channel_total, IFNULL(latest.channel_pf, 0) + IFNULL(arc.t_pf, 0) AS total_channel_pf, IFNULL(latest.channel_zs, 0) + IFNULL(arc.t_zs, 0) AS total_channel_zs, IFNULL(latest.channel_jt, 0) + IFNULL(arc.t_jt, 0) AS total_channel_jt, IFNULL(latest.channel_al, 0) + IFNULL(arc.t_al, 0) AS total_channel_al, IFNULL(latest.channel_jj, 0) + IFNULL(arc.t_jj, 0) AS total_channel_jj, IFNULL(latest.channel_pf, 0) + IFNULL(latest.channel_zs, 0) + IFNULL(latest.channel_jt, 0) + IFNULL(latest.channel_al, 0) + IFNULL(latest.channel_jj, 0) + IFNULL(arc.t_sum, 0) AS total_channel_total FROM ( SELECT SUM(IFNULL(a.channel_pf, 0)) AS t_pf, SUM(IFNULL(a.channel_zs, 0)) AS t_zs, SUM(IFNULL(a.channel_jt, 0)) AS t_jt, SUM(IFNULL(a.channel_al, 0)) AS t_al, SUM(IFNULL(a.channel_jj, 0)) AS t_jj, SUM( IFNULL(a.channel_pf, 0) + IFNULL(a.channel_zs, 0) + IFNULL(a.channel_jt, 0) + IFNULL(a.channel_al, 0) + IFNULL(a.channel_jj, 0) ) AS t_sum FROM pf_profit_archive a WHERE a.book_id = ${@book_id}
AND a.cost_date <= ${@cost_date}
) arc LEFT JOIN ( SELECT p.channel_pf, p.channel_zs, p.channel_jt, p.channel_al, p.channel_jj FROM pf_profit_record p WHERE p.book_id = ${@book_id}
AND p.cost_date <= ${@cost_date}
ORDER BY p.cost_date DESC LIMIT 1 ) latest ON TRUE
